// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract VulnerabilityPlatform {
    enum Role { None, Researcher, Organization, Validator }
    enum ReportStatus { Submitted, Acknowledged, Validated, Rejected, Disputed, Resolved }

    struct UserProfile {
        Role role;
        string name;
        string profileCid; // IPFS CID for detailed identity (company info, certs, etc.)
        bool isRegistered;
    }

    struct Report {
        uint256 id;
        address researcher;
        address organization;
        string cid; // IPFS Content Identifier
        string rejectionCid; // IPFS CID for Org's Rejection Reason
        string disputeCid; // IPFS CID for Researcher's Dispute Claim
        ReportStatus status;
        uint256 timestamp;
    }

    struct Comment {
        address sender;
        string messageCid; // IPFS CID of the comment JSON
        uint256 timestamp;
    }

    struct BountyProgram {
        uint256 id;
        address organization;
        string detailsCid;    // IPFS CID: name, scope, description, bounty tiers
        bool active;
        uint256 createdAt;
    }

    mapping(address => UserProfile) public users;
    mapping(uint256 => Report) public reports;
    mapping(address => uint256) public orgVaults; // The Escrow Vaults
    uint256 public reportCount;

    // On-chain Bounty Programs
    uint256 public programCount;
    mapping(uint256 => BountyProgram) public programs;
    mapping(address => uint256[]) public orgProgramIds;

    // Program Enrollment: programId => enrolled researcher addresses
    mapping(uint256 => address[]) public programResearchers;
    mapping(uint256 => mapping(address => bool)) public isEnrolled; // Quick lookup

    // On-chain Comment Threads: reportId => comments array
    mapping(uint256 => Comment[]) private reportComments;

    // Report Collaborators & Split Payout percentages (1-100)
    mapping(uint256 => address[]) public reportCollaborators;
    mapping(uint256 => uint256[]) public reportCollaboratorSplits;

    event UserRegistered(address indexed user, Role role, string name, string profileCid);
    event ReportSubmitted(uint256 indexed id, address indexed researcher, address indexed organization, string cid);
    event StatusChanged(uint256 indexed id, ReportStatus status, address indexed updatedBy);
    event DisputeRaised(uint256 indexed id, address indexed validator, string reason);
    event VaultFunded(address indexed org, uint256 amount);
    event PayoutReleased(uint256 indexed reportId, address indexed researcher, address indexed validator, uint256 amount);
    event ResearcherEnrolled(uint256 indexed programId, address indexed researcher);
    event ResearcherUnenrolled(uint256 indexed programId, address indexed researcher);
    event CommentAdded(uint256 indexed reportId, address indexed sender, string messageCid);
    event ProgramCreated(uint256 indexed id, address indexed org, string detailsCid);
    event ProgramUpdated(uint256 indexed id, bool active);
    event ProgramMetadataUpdated(uint256 indexed id, address indexed org, string newDetailsCid);

    modifier onlyRole(Role _role) {
        require(users[msg.sender].role == _role, "Unauthorized: Invalid Role");
        _;
    }

    modifier onlyRegistered() {
        require(users[msg.sender].isRegistered, "Unauthorized: Not Registered");
        _;
    }

    function registerUser(Role _role, string memory _name, string memory _profileCid) external {
        require(!users[msg.sender].isRegistered, "Already registered");
        require(_role != Role.None, "Invalid role");
        users[msg.sender] = UserProfile(_role, _name, _profileCid, true);
        emit UserRegistered(msg.sender, _role, _name, _profileCid);
    }

    function updateProfile(string memory _name, string memory _profileCid) external onlyRegistered {
        require(bytes(_name).length > 0, "Name cannot be empty");
        users[msg.sender].name = _name;
        users[msg.sender].profileCid = _profileCid;
        emit UserRegistered(msg.sender, users[msg.sender].role, _name, _profileCid);
    }

    function submitReport(
        address _organization, 
        string memory _cid, 
        address[] memory _collaborators, 
        uint256[] memory _splits
    ) external onlyRole(Role.Researcher) {
        require(users[_organization].role == Role.Organization, "Target is not an Organization");
        require(_collaborators.length == _splits.length, "Mismatched collaborators and splits");
        
        uint256 totalSplit = 0;
        for (uint256 i = 0; i < _splits.length; i++) {
            require(_collaborators[i] != address(0), "Invalid collaborator address");
            require(_collaborators[i] != msg.sender, "Primary researcher cannot be a collaborator");
            totalSplit += _splits[i];
        }
        require(totalSplit <= 100, "Total split exceeds 100%");

        reportCount++;
        reports[reportCount] = Report({
            id: reportCount,
            researcher: msg.sender,
            organization: _organization,
            cid: _cid,
            rejectionCid: "",
            disputeCid: "",
            status: ReportStatus.Submitted,
            timestamp: block.timestamp
        });
        
        reportCollaborators[reportCount] = _collaborators;
        reportCollaboratorSplits[reportCount] = _splits;
        
        emit ReportSubmitted(reportCount, msg.sender, _organization, _cid);
    }

    function fundVault() external payable onlyRole(Role.Organization) {
        orgVaults[msg.sender] += msg.value;
        emit VaultFunded(msg.sender, msg.value);
    }

    function updateStatus(uint256 _reportId, ReportStatus _newStatus) external {
        Report storage report = reports[_reportId];
        require(report.id != 0, "Report does not exist");
        
        // Organization can acknowledge or validate directly
        if (users[msg.sender].role == Role.Organization) {
            require(report.organization == msg.sender, "Not the target organization");
            require(
                _newStatus == ReportStatus.Acknowledged || 
                _newStatus == ReportStatus.Validated,
                "Invalid status transition for Organization"
            );
        } else {
            revert("Unauthorized to update status");
        }

        report.status = _newStatus;
        emit StatusChanged(_reportId, _newStatus, msg.sender);
    }

    function rejectReport(uint256 _reportId, string memory _rejectionCid) external onlyRole(Role.Organization) {
        Report storage report = reports[_reportId];
        require(report.id != 0, "Report does not exist");
        require(report.organization == msg.sender, "Not the target organization");
        require(report.status == ReportStatus.Acknowledged || report.status == ReportStatus.Submitted, "Invalid status transition");

        report.status = ReportStatus.Rejected;
        report.rejectionCid = _rejectionCid;
        emit StatusChanged(_reportId, ReportStatus.Rejected, msg.sender);
    }

    function raiseDispute(uint256 _reportId, string memory _disputeCid) external onlyRole(Role.Researcher) {
        Report storage report = reports[_reportId];
        require(report.id != 0, "Report does not exist");
        require(report.researcher == msg.sender, "Not the reporter");
        require(report.status == ReportStatus.Rejected, "Can only dispute Rejected reports");

        report.status = ReportStatus.Disputed;
        report.disputeCid = _disputeCid;
        emit StatusChanged(_reportId, ReportStatus.Disputed, msg.sender);
        emit DisputeRaised(_reportId, msg.sender, _disputeCid);
    }

    function payBounty(uint256 _reportId, uint256 _bountyAmount) external onlyRole(Role.Organization) {
        Report storage report = reports[_reportId];
        require(report.id != 0, "Report does not exist");
        require(report.organization == msg.sender, "Not the target organization");
        require(report.status == ReportStatus.Validated || report.status == ReportStatus.Resolved, "Report must be Validated");
        require(orgVaults[msg.sender] >= _bountyAmount, "Insufficient vault balance");

        orgVaults[msg.sender] -= _bountyAmount;
        report.status = ReportStatus.Resolved; // Mark as resolved (paid)

        address[] memory collabs = reportCollaborators[_reportId];
        uint256[] memory splits = reportCollaboratorSplits[_reportId];

        uint256 totalPaidToCollabs = 0;
        for (uint256 i = 0; i < collabs.length; i++) {
            uint256 collabAmount = (_bountyAmount * splits[i]) / 100;
            if (collabAmount > 0) {
                totalPaidToCollabs += collabAmount;
                payable(collabs[i]).transfer(collabAmount);
                emit PayoutReleased(_reportId, collabs[i], address(0), collabAmount);
            }
        }

        uint256 primaryAmount = _bountyAmount - totalPaidToCollabs;
        if (primaryAmount > 0) {
            payable(report.researcher).transfer(primaryAmount);
            emit PayoutReleased(_reportId, report.researcher, address(0), primaryAmount);
        }
    }

    function resolveDispute(uint256 _reportId, bool _isValid, uint256 _bountyAmount) external onlyRole(Role.Validator) {
        Report storage report = reports[_reportId];
        require(report.id != 0, "Report does not exist");
        require(report.status == ReportStatus.Disputed, "Report is not disputed");
        
        address org = report.organization;

        if (_isValid) {
            require(orgVaults[org] >= _bountyAmount, "Org vault insufficient");
            orgVaults[org] -= _bountyAmount;
            
            uint256 validatorCut = (_bountyAmount * 10) / 100;
            payable(msg.sender).transfer(validatorCut);

            address[] memory collabs = reportCollaborators[_reportId];
            uint256[] memory splits = reportCollaboratorSplits[_reportId];

            uint256 totalPaidToCollabs = 0;
            for (uint256 i = 0; i < collabs.length; i++) {
                uint256 collabAmount = (_bountyAmount * splits[i]) / 100;
                if (collabAmount > 0) {
                    totalPaidToCollabs += collabAmount;
                    payable(collabs[i]).transfer(collabAmount);
                    emit PayoutReleased(_reportId, collabs[i], msg.sender, collabAmount);
                }
            }

            uint256 primaryAmount = _bountyAmount - validatorCut - totalPaidToCollabs;
            if (primaryAmount > 0) {
                payable(report.researcher).transfer(primaryAmount);
                emit PayoutReleased(_reportId, report.researcher, msg.sender, primaryAmount);
            }
            
            report.status = ReportStatus.Resolved;
        } else {
            // Validator rules as Invalid. Case closed.
            report.status = ReportStatus.Rejected;
            emit StatusChanged(_reportId, ReportStatus.Rejected, msg.sender);
        }
    }

    // ─────────────────────────────────────────────────────
    // ON-CHAIN BOUNTY PROGRAMS
    // ─────────────────────────────────────────────────────

    function createProgram(string memory _detailsCid) external onlyRole(Role.Organization) {
        programCount++;
        programs[programCount] = BountyProgram(programCount, msg.sender, _detailsCid, true, block.timestamp);
        orgProgramIds[msg.sender].push(programCount);
        emit ProgramCreated(programCount, msg.sender, _detailsCid);
    }

    function toggleProgram(uint256 _programId) external onlyRole(Role.Organization) {
        require(programs[_programId].organization == msg.sender, "Not your program");
        programs[_programId].active = !programs[_programId].active;
        emit ProgramUpdated(_programId, programs[_programId].active);
    }

    function updateProgram(uint256 _programId, string memory _newDetailsCid) external onlyRole(Role.Organization) {
        require(programs[_programId].organization == msg.sender, "Not your program");
        require(programs[_programId].id != 0, "Program does not exist");
        programs[_programId].detailsCid = _newDetailsCid;
        emit ProgramMetadataUpdated(_programId, msg.sender, _newDetailsCid);
    }

    function getOrgPrograms(address _org) external view returns (uint256[] memory) {
        return orgProgramIds[_org];
    }

    function getProgramCount() external view returns (uint256) {
        return programCount;
    }

    // ─────────────────────────────────────────────────────
    // PROGRAM ENROLLMENT — Researchers join bounty programs
    // ─────────────────────────────────────────────────────

    function joinProgram(uint256 _programId) external onlyRole(Role.Researcher) {
        require(programs[_programId].id != 0, "Program does not exist");
        require(programs[_programId].active, "Program is not active");
        require(!isEnrolled[_programId][msg.sender], "Already enrolled in this program");
        programResearchers[_programId].push(msg.sender);
        isEnrolled[_programId][msg.sender] = true;
        emit ResearcherEnrolled(_programId, msg.sender);
    }

    function leaveProgram(uint256 _programId) external onlyRole(Role.Researcher) {
        require(programs[_programId].id != 0, "Program does not exist");
        require(isEnrolled[_programId][msg.sender], "Not enrolled in this program");

        isEnrolled[_programId][msg.sender] = false;

        uint256 length = programResearchers[_programId].length;
        for (uint256 i = 0; i < length; i++) {
            if (programResearchers[_programId][i] == msg.sender) {
                programResearchers[_programId][i] = programResearchers[_programId][length - 1];
                programResearchers[_programId].pop();
                break;
            }
        }

        emit ResearcherUnenrolled(_programId, msg.sender);
    }

    function getProgramResearchers(uint256 _programId) external view returns (address[] memory) {
        return programResearchers[_programId];
    }

    function getProgramResearcherCount(uint256 _programId) external view returns (uint256) {
        return programResearchers[_programId].length;
    }

    // ─────────────────────────────────────────────────────
    // ON-CHAIN COMMENTS — Auditable report discussion
    // ─────────────────────────────────────────────────────

    function addComment(uint256 _reportId, string memory _messageCid) external onlyRegistered {
        Report storage report = reports[_reportId];
        require(report.id != 0, "Report does not exist");
        // Only the researcher who filed it or the target org can comment
        require(
            msg.sender == report.researcher || msg.sender == report.organization,
            "Not authorized to comment on this report"
        );

        reportComments[_reportId].push(Comment({
            sender: msg.sender,
            messageCid: _messageCid,
            timestamp: block.timestamp
        }));

        emit CommentAdded(_reportId, msg.sender, _messageCid);
    }

    function getComments(uint256 _reportId) external view returns (Comment[] memory) {
        return reportComments[_reportId];
    }

    function getCommentCount(uint256 _reportId) external view returns (uint256) {
        return reportComments[_reportId].length;
    }
}

